import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack, LinearProgress } from '@mui/material';
import { ResponsiveChartContainer, LinePlot, ChartsXAxis, ChartsYAxis, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface CurrentMilestone {
  name: string;
  progress: number;
  deadline: string;
}

interface UpcomingMilestone {
  name: string;
  start: string;
  end: string;
}

interface TimelineProgress {
  date: string;
  progress: number;
}

interface ProjectData {
  projectName: string;
  currentMilestone: CurrentMilestone;
  upcomingMilestones: UpcomingMilestone[];
  timelineProgress: TimelineProgress[];
}

export default function Widget() {
  const projectData = response.data as ProjectData;
  const { projectName, currentMilestone, timelineProgress } = projectData;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ mb: 1, color: '#FF5722' }}>
              {projectName}
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Current Milestone: {currentMilestone.name}
            </Typography>
            <Typography variant="body2" color="text.secondary" sx={{ mb: 1 }}>
              Deadline: {currentMilestone.deadline}
            </Typography>
            <LinearProgress
              variant="determinate"
              value={currentMilestone.progress}
              sx={{
                height: 8,
                borderRadius: 4,
                bgcolor: '#FFC107',
                '& .MuiLinearProgress-bar': {
                  bgcolor: '#FF5722',
                  borderRadius: 4,
                },
              }}
            />
          </Box>

          <Box sx={{ width: '100%', height: 150 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'line',
                  data: timelineProgress.map(tp => tp.progress),
                  color: '#FF5722',
                  curve: 'linear',
                },
              ]}
              xAxis={[
                {
                  data: timelineProgress.map(tp => tp.date),
                  scaleType: 'point',
                  tickLabelStyle: { fontSize: 10, fill: '#6B7280' },
                },
              ]}
              yAxis={[{ id: 'progress', tickLabelStyle: { fontSize: 10, fill: '#6B7280' } }]}
            >
              <ChartsClipPath id={clipPathId} />
              <g clipPath={`url(#${clipPathId})`}>
                <LinePlot />
              </g>
              <ChartsXAxis axisId="date" />
              <ChartsYAxis axisId="progress" />
            </ResponsiveChartContainer>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
